package org.eclipse.jdt.internal.ui.text.java;

import org.eclipse.jface.text.templates.Template;
import org.eclipse.jdt.internal.ui.text.template.contentassist.TemplateProposal;

public class AbstractTemplateCompletionProposalComputer {
    void process(TemplateProposal curr) {
        Template template = curr.getTemplate();
        String name = template.getPattern();
        System.out.println(name);
    }

    void anotherMethod(Template templateObj) {
        String name = templateObj.getPattern();
        System.out.println(name);
    }

    class OtherTemplate {
        public String getPattern() { return "other pattern"; }
    }
    void negativeCase(OtherTemplate other) {
        String name = other.getPattern();
        System.out.println(name);
    }
}

